const TEST_CANDIDATE_ID = '15250bc9-581f-4710-8a7f-ba5dd5b5e164';
const TEST_WEBSITE = '';

const allowedStatuses = ['review', 'competitor_review'];
const requestedId = TEST_CANDIDATE_ID.trim();
const requestedWebsite = TEST_WEBSITE.trim().toLowerCase();

if (!requestedId && !requestedWebsite) {
  throw new Error('安全停止：必须在 Code 节点中填写 TEST_CANDIDATE_ID 或 TEST_WEBSITE，且只能提升一个明确测试候选。');
}

const matches = items.filter((item) => {
  const row = item.json;
  if (!allowedStatuses.includes(row.candidate_status)) {
    return false;
  }

  if (requestedId) {
    return String(row.id || '').toLowerCase() === requestedId.toLowerCase();
  }

  return String(row.website || '').toLowerCase() === requestedWebsite;
});

if (matches.length === 0) {
  throw new Error('安全停止：没有找到匹配的 review 或 competitor_review 候选，未提升任何记录。');
}

if (matches.length > 1) {
  throw new Error('安全停止：匹配到多条候选，必须使用唯一 candidate ID 或唯一 website。');
}

const candidate = matches[0].json;

if (!allowedStatuses.includes(candidate.candidate_status)) {
  throw new Error('安全停止：候选状态不是 review 或 competitor_review，禁止提升。');
}

return [{
  json: {
    candidate_lead_id: candidate.id,
    company_name: candidate.company_name || candidate.page_title || 'Unknown company',
    website: candidate.website || null,
    country: candidate.country || null,
    industry: candidate.industry || null,
    source: candidate.source || 'candidate_leads',
    source_url: candidate.source_url || null,
    search_query: candidate.search_query || null,
    page_title: candidate.page_title || null,
    page_snippet: candidate.page_snippet || null,
    candidate_status: candidate.candidate_status,
    relevance_score: candidate.relevance_score ?? null,
    review_notes: candidate.review_notes || null,
    candidate_raw_data: candidate.raw_data || {},
  },
}];
